// ============================================================================
// Section 1: Big-Endian Helper Tests
// ============================================================================

TEST(pack_read_be32_basic) {
    // Big-endian: 0x01020304 stored as bytes [01, 02, 03, 04]
    uint8_t data[] = { 0x01, 0x02, 0x03, 0x04 };
    uint32_t result = test_read_be32(data);
    TEST_ASSERT_EQ(result, 0x01020304u);
}

TEST(pack_read_be64_basic) {
    // Big-endian 64-bit value
    uint8_t data[] = { 0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08 };
    uint64_t result = test_read_be64(data);
    TEST_ASSERT_EQ(result, 0x0102030405060708ULL);
}

TEST(pack_read_be32_all_bits) {
    // Test all bits set
    uint8_t data[] = { 0xFF, 0xFF, 0xFF, 0xFF };
    uint32_t result = test_read_be32(data);
    TEST_ASSERT_EQ(result, 0xFFFFFFFFu);

    // Test high bit only
    uint8_t high_bit[] = { 0x80, 0x00, 0x00, 0x00 };
    result = test_read_be32(high_bit);
    TEST_ASSERT_EQ(result, 0x80000000u);
}

// ============================================================================
// Section 2: Varint Decoding Tests
// ============================================================================

TEST(pack_varint_single_byte_commit) {
    // Single byte: type=1 (commit), size=10
    // Format: 0TTTSSSS where TTT=001, SSSS=1010 -> 0x1A
    uint8_t data[] = { 0x1A };
    const uint8_t* ptr = data;
    int type = 0;
    uint64_t size = test_read_pack_varint_size(&ptr, &type);
    TEST_ASSERT_EQ(type, Git::OBJ_COMMIT);
    TEST_ASSERT_EQ(size, 10ULL);
    TEST_ASSERT_EQ(ptr, data + 1);
}

TEST(pack_varint_single_byte_tree) {
    // Single byte: type=2 (tree), size=5
    // Format: 0TTTSSSS where TTT=010, SSSS=0101 -> 0x25
    uint8_t data[] = { 0x25 };
    const uint8_t* ptr = data;
    int type = 0;
    uint64_t size = test_read_pack_varint_size(&ptr, &type);
    TEST_ASSERT_EQ(type, Git::OBJ_TREE);
    TEST_ASSERT_EQ(size, 5ULL);
}

TEST(pack_varint_single_byte_blob) {
    // Single byte: type=3 (blob), size=15
    // Format: 0TTTSSSS where TTT=011, SSSS=1111 -> 0x3F
    uint8_t data[] = { 0x3F };
    const uint8_t* ptr = data;
    int type = 0;
    uint64_t size = test_read_pack_varint_size(&ptr, &type);
    TEST_ASSERT_EQ(type, Git::OBJ_BLOB);
    TEST_ASSERT_EQ(size, 15ULL);
}

TEST(pack_varint_two_bytes) {
    // Two bytes: type=1 (commit), size larger than 15
    // First byte has continuation bit set (0x80)
    // Format: 1TTTSSSS 0SSSSSSS
    // Size = first_4_bits + (second_7_bits << 4)
    // Example: size=100 = 4 + (6 << 4) = 4 + 96
    // type=1: 0x80 | 0x10 | 0x04 = 0x94, second byte = 0x06
    uint8_t data[] = { 0x94, 0x06 };
    const uint8_t* ptr = data;
    int type = 0;
    uint64_t size = test_read_pack_varint_size(&ptr, &type);
    TEST_ASSERT_EQ(type, Git::OBJ_COMMIT);
    TEST_ASSERT_EQ(size, 100ULL);
    TEST_ASSERT_EQ(ptr, data + 2);
}

TEST(pack_varint_three_bytes) {
    // Three bytes for larger sizes
    // Size = first_4_bits + (second_7_bits << 4) + (third_7_bits << 11)
    // Example: size=10000 = 0 + (48 << 4) + (4 << 11) = 768 + 8192 + ...
    // Actually let's compute: 10000 = 0x2710
    // size bits: 0000 (first 4) | 1110001 (next 7) | 0000100 (next 7)
    // = 0 | (113 << 4) | (4 << 11) = 1808 + 8192 = 9999... let me recalculate
    // 10000 in the varint format:
    // low 4 bits: 10000 & 0xF = 0
    // next 7 bits: (10000 >> 4) & 0x7F = 625 & 127 = 113
    // next 7 bits: (10000 >> 11) & 0x7F = 4
    // So: type=3, bytes = 0x80|0x30|0x00, 0x80|0x71, 0x04
    uint8_t data[] = { 0xB0, 0xF1, 0x04 };  // type=3, size=10000
    const uint8_t* ptr = data;
    int type = 0;
    uint64_t size = test_read_pack_varint_size(&ptr, &type);
    TEST_ASSERT_EQ(type, Git::OBJ_BLOB);
    TEST_ASSERT_EQ(size, 10000ULL);
    TEST_ASSERT_EQ(ptr, data + 3);
}

TEST(pack_varint_ofs_delta_type) {
    // Type 6 = OFS_DELTA
    // Single byte: type=6, size=8
    uint8_t data[] = { 0x68 };  // 0110 1000 = type 6, size 8
    const uint8_t* ptr = data;
    int type = 0;
    uint64_t size = test_read_pack_varint_size(&ptr, &type);
    TEST_ASSERT_EQ(type, Git::OBJ_OFS_DELTA);
    TEST_ASSERT_EQ(size, 8ULL);
}

