static const wchar_t* PACK_FIXTURE_DIR = L"test\\fixtures\\packs";

// Helper to check if fixture exists
static bool pack_fixture_exists() {
    wchar_t path[512];
    swprintf_s(path, 512, L"%s\\minimal.idx", PACK_FIXTURE_DIR);
    DWORD attrs = GetFileAttributesW(path);
    return attrs != INVALID_FILE_ATTRIBUTES;
}

