TEST(pack_integration_fanout_monotonic) {
    if (!pack_fixture_exists()) {
        TEST_SKIP("Pack fixtures not found");
    }

    wchar_t idx_path[512];
    swprintf_s(idx_path, 512, L"%s\\minimal.idx", PACK_FIXTURE_DIR);

    MemoryMap* mmap = mmap_open(idx_path);
    TEST_ASSERT_NOT_NULL(mmap);

    GitPackIndex idx = {};
    bool result = test_parse_pack_index(&idx, mmap);
    TEST_ASSERT_TRUE(result);

    // Fanout table must be monotonically increasing
    uint32_t prev = 0;
    for (int i = 0; i < 256; i++) {
        uint32_t val = test_read_be32(&idx.fanout[i]);
        TEST_ASSERT_TRUE(val >= prev);
        prev = val;
    }

    // Last fanout entry equals total object count
    TEST_ASSERT_EQ(test_read_be32(&idx.fanout[255]), idx.object_count);

    mmap_close(mmap);
}

TEST(pack_integration_find_object) {
    if (!pack_fixture_exists()) {
        TEST_SKIP("Pack fixtures not found");
    }

    wchar_t idx_path[512];
    swprintf_s(idx_path, 512, L"%s\\minimal.idx", PACK_FIXTURE_DIR);

    MemoryMap* mmap = mmap_open(idx_path);
    TEST_ASSERT_NOT_NULL(mmap);

    GitPackIndex idx = {};
    bool result = test_parse_pack_index(&idx, mmap);
    TEST_ASSERT_TRUE(result);

    // Get the first SHA from the sha_table
    const uint8_t* first_sha = idx.sha_table;

    // Should find it at index 0
    int64_t found_idx = test_pack_index_find(&idx, first_sha);
    TEST_ASSERT_TRUE(found_idx >= 0);

    // Search for a non-existent SHA (all zeros)
    uint8_t zero_sha[20] = {0};
    int64_t not_found = test_pack_index_find(&idx, zero_sha);
    TEST_ASSERT_EQ(not_found, -1LL);

    mmap_close(mmap);
}

